window.addEventListener('error',e=>showError(e.message));window.addEventListener('unhandledrejection',e=>showError(e.reason?.message||String(e.reason)));
function showError(t){$('#error').style.display='block';$('#error').textContent='运行错误：'+t}

initRenderer();loadAssets();
function initRenderer(){scene=new THREE.Scene();scene.background=new THREE.Color(0x07121c);scene.fog=new THREE.FogExp2(0x132331,.012);camera=new THREE.PerspectiveCamera(43,innerWidth/innerHeight,.1,250);renderer=new THREE.WebGLRenderer({antialias:true,powerPreference:'high-performance'});renderer.setPixelRatio(Math.min(devicePixelRatio,1.7));renderer.setSize(innerWidth,innerHeight);renderer.shadowMap.enabled=true;renderer.shadowMap.type=THREE.PCFSoftShadowMap;renderer.outputColorSpace=THREE.SRGBColorSpace;renderer.toneMapping=THREE.ACESFilmicToneMapping;renderer.toneMappingExposure=1.02;document.body.prepend(renderer.domElement);clock=new THREE.Clock();raycaster=new THREE.Raycaster();addEventListener('resize',()=>{camera.aspect=innerWidth/innerHeight;camera.updateProjectionMatrix();renderer.setSize(innerWidth,innerHeight)})}
function loadAssets(){for(let i=0;i<6;i++)loader.load(`./models/hero-${i}.glb`,g=>{g.scene.traverse(o=>{if(o.isMesh){o.castShadow=true;o.receiveShadow=true}});templates[i]=g.scene;animations[i]=g.animations;assetDone()},undefined,e=>{showError(`英雄${i+1}模型加载失败`);console.error(e)})}
function assetDone(){loaded++;$('#progress').style.width=(loaded/6*100)+'%';$('#loadText').textContent=`已唤醒 ${loaded}/6 位英雄`;if(loaded===6){setTimeout(()=>{$('#loading').classList.add('hidden');buildCards();$('#select').classList.remove('hidden');initHeroPreview()},250)}}
function buildCards(){initRoomLobby();const box=$('#cards');box.innerHTML='';defs.forEach((d,i)=>{let b=document.createElement('button');b.className='card'+(i===selectedHero?' selected':'');b.dataset.hero=i;b.innerHTML=`<div class="portrait" style="color:#${d.color.toString(16).padStart(6,'0')}">${d.icon}</div><small>${d.role}</small><strong>${d.name}</strong><p>${d.desc}</p><em>${d.skills.join(' · ')}</em>`;b.onclick=()=>selectHeroPreview(i);b.onpointerenter=()=>{if(matchMedia('(hover:hover)').matches)selectHeroPreview(i)};box.appendChild(b)});$('#enterBattle').onclick=()=>startSelected()}
function startSelected(){if(room.mode==='online'){if(!room.channel||!room.peer){setRoomStatus('请先创建或加入房间，并等待队友加入');return}room.ready=true;room.channel.postMessage({type:'ready',hero:selectedHero});syncRoom();if(!room.host){setRoomStatus('已准备，等待房主开局');return}room.channel.postMessage({type:'start',hero:selectedHero});}start(selectedHero)}
function roomCode(){return Math.random().toString(36).slice(2,8).toUpperCase()}
function setRoomStatus(text){const el=$('#roomStatus');if(el)el.textContent=text}
function closeRoom(){if(room.channel)room.channel.close();room={mode:room.mode,code:'',channel:null,host:false,peer:false,ready:false}}
function syncRoom(){const b=$('#readyRoom');if(!b)return;b.disabled=!room.peer||room.ready;b.textContent=room.ready?'已准备':'准备开局';if(room.mode==='online'&&room.peer&&!room.ready)setRoomStatus(room.host?'队友已加入，选择英雄后开始':'已进入房间，选择英雄并准备')}
function openRoom(code,host){closeRoom();room.code=code;room.host=host;room.channel=new BroadcastChannel('arena-3d-room-'+code);room.channel.onmessage=e=>{const m=e.data;if(!m||m.type==='hello')return;if(m.type==='join'){room.peer=true;room.channel.postMessage({type:'presence'});syncRoom()}if(m.type==='presence'){room.peer=true;syncRoom()}if(m.type==='ready'){room.peer=true;setRoomStatus(`队友已锁定 ${defs[m.hero]?.name||'英雄'}`);syncRoom()}if(m.type==='start'&&!room.host){setRoomStatus('房主已开局，进入战场');start(selectedHero)}};room.channel.postMessage({type:'join'});setRoomStatus(host?`房间 ${code} 已创建，等待队友`:`已加入房间 ${code}，正在呼叫房主`);syncRoom()}
function initRoomLobby(){if($('#roomPanel').dataset.bound)return;$('#roomPanel').dataset.bound='1';document.querySelectorAll('.mode-tab').forEach(b=>b.onclick=()=>{room.mode=b.dataset.mode;document.querySelectorAll('.mode-tab').forEach(x=>x.classList.toggle('active',x===b));$('#roomPanel').classList.toggle('open',room.mode==='online');if(room.mode==='solo')closeRoom();else setRoomStatus('创建房间，或输入房间码加入')});$('#createRoom').onclick=()=>{let code=roomCode();$('#roomCode').value=code;openRoom(code,true)};$('#joinRoom').onclick=()=>{let code=$('#roomCode').value.trim().toUpperCase();if(!/^[A-Z0-9]{4,6}$/.test(code)){setRoomStatus('请输入 4–6 位字母或数字房间码');return}openRoom(code,false)};$('#readyRoom').onclick=()=>startSelected()}

function cloneSkinnedModel(source){const sourceLookup=new Map(),cloneLookup=new Map(),clone=source.clone(true);parallelTraverse(source,clone,(a,b)=>{sourceLookup.set(b,a);cloneLookup.set(a,b)});clone.traverse(node=>{if(!node.isSkinnedMesh)return;const sourceMesh=sourceLookup.get(node);node.skeleton=sourceMesh.skeleton.clone();node.bindMatrix.copy(sourceMesh.bindMatrix);node.skeleton.bones=sourceMesh.skeleton.bones.map(bone=>cloneLookup.get(bone));node.bind(node.skeleton,node.bindMatrix)});return clone}
function parallelTraverse(a,b,callback){callback(a,b);for(let i=0;i<a.children.length;i++)parallelTraverse(a.children[i],b.children[i],callback)}
function initHeroPreview(){const host=$('#heroPreview'),pScene=new THREE.Scene(),pCamera=new THREE.PerspectiveCamera(32,1,.05,100),pRenderer=new THREE.WebGLRenderer({antialias:true,alpha:true,powerPreference:'high-performance'}),heroRoot=new THREE.Group();pRenderer.setPixelRatio(Math.min(devicePixelRatio,1.6));pRenderer.outputColorSpace=THREE.SRGBColorSpace;pRenderer.toneMapping=THREE.ACESFilmicToneMapping;pRenderer.toneMappingExposure=1.18;pRenderer.shadowMap.enabled=true;host.appendChild(pRenderer.domElement);pScene.add(new THREE.HemisphereLight(0xb9dcff,0x172034,2.2));let key=new THREE.DirectionalLight(0xffdfb5,4.3);key.position.set(-3,7,5);key.castShadow=true;pScene.add(key);let rim=new THREE.DirectionalLight(0x59bfff,3.2);rim.position.set(4,4,-4);pScene.add(rim);let floor=new THREE.Mesh(new THREE.CircleGeometry(3.5,48),new THREE.MeshStandardMaterial({color:0x172a3f,metalness:.22,roughness:.58}));floor.rotation.x=-Math.PI/2;floor.receiveShadow=true;pScene.add(floor,heroRoot);pCamera.position.set(0,2.7,8);pCamera.lookAt(0,2.15,0);const resize=()=>{let r=host.getBoundingClientRect(),w=Math.max(1,r.width),h=Math.max(1,r.height);pRenderer.setSize(w,h,false);pCamera.aspect=w/h;pCamera.updateProjectionMatrix()};let dragging=false,lastX=0;const down=e=>{dragging=true;lastX=e.clientX;pRenderer.domElement.setPointerCapture?.(e.pointerId)},move=e=>{if(!dragging)return;heroRoot.rotation.y+=(e.clientX-lastX)*.012;lastX=e.clientX},up=()=>dragging=false;pRenderer.domElement.addEventListener('pointerdown',down);pRenderer.domElement.addEventListener('pointermove',move);pRenderer.domElement.addEventListener('pointerup',up);pRenderer.domElement.addEventListener('pointercancel',up);let observer=new ResizeObserver(resize);observer.observe(host);preview={scene:pScene,camera:pCamera,renderer:pRenderer,root:heroRoot,mixer:null,model:null,active:true,last:performance.now(),observer};resize();selectHeroPreview(selectedHero);requestAnimationFrame(previewLoop)}
function selectHeroPreview(id){selectedHero=id;document.querySelectorAll('.card').forEach((card,i)=>card.classList.toggle('selected',i===id));$('#previewRole').textContent=`${defs[id].role} · ${defs[id].skills.join(' / ')}`;$('#previewName').textContent=defs[id].name;$('#previewDesc').textContent=defs[id].desc+' · 拖动旋转';if(!preview)return;if(preview.mixer){preview.mixer.stopAllAction();preview.mixer.uncacheRoot(preview.model)}if(preview.model)preview.root.remove(preview.model);let model=cloneSkinnedModel(templates[id]);model.traverse(o=>{if(o.isMesh){o.castShadow=true;o.receiveShadow=true}});let box=new THREE.Box3().setFromObject(model),size=box.getSize(new THREE.Vector3()),scale=4.35/Math.max(size.y,.001);model.scale.setScalar(scale);box.setFromObject(model);let center=box.getCenter(new THREE.Vector3());model.position.set(-center.x,-box.min.y,-center.z);preview.root.add(model);preview.root.rotation.y=.25;preview.model=model;preview.mixer=new THREE.AnimationMixer(model);let clip=animations[id].find(a=>a.name.toLowerCase()==='idle')||animations[id].find(a=>a.name.toLowerCase().includes('idle'))||animations[id][0];if(clip)preview.mixer.clipAction(clip).play()}
function previewLoop(now){if(!preview?.active)return;let dt=Math.min(.05,(now-preview.last)/1000);preview.last=now;preview.mixer?.update(dt);preview.root.rotation.y+=dt*.18;preview.renderer.render(preview.scene,preview.camera);requestAnimationFrame(previewLoop)}
function stopHeroPreview(){if(!preview)return;preview.active=false;preview.observer.disconnect();preview.mixer?.stopAllAction();preview.renderer.dispose();preview.renderer.domElement.remove();preview=null}

function start(pick){stopHeroPreview();$('#select').classList.add('hidden');$('#hud').classList.remove('hidden');buildWorld();const rest=[0,1,2,3,4,5].filter(i=>i!==pick),order=[pick,...rest];game={time:0,last:performance.now(),heroes:[],minions:[],shots:[],zones:[],structures:[],effects:[],blueKills:0,redKills:0,wave:1,over:false,player:null,utility:{recall:0,heal:0,flash:0}};order.slice(0,3).forEach((id,i)=>spawnHero(id,0,new THREE.Vector3(-48+i*1.8,0,-5+i*5),i===0));order.slice(3).forEach((id,i)=>spawnHero(id,1,new THREE.Vector3(48-i*1.8,0,-5+i*5)));spawnStructures();buildTeamStrip();initShopUI();updateGold();document.querySelectorAll('.shopItem').forEach(b=>b.classList.remove('owned'));feed('战斗开始：摧毁敌方诸界核心！',0xffdc80);clock.start();requestAnimationFrame(loop)}
function buildTeamStrip(){let box=$('#teamStrip');box.innerHTML='';for(const h of game.heroes){let face=document.createElement('div');face.className='team-face'+(h.team?' enemy':'');face.textContent=h.def.icon;face.title=`${h.team?'赤渊':'苍穹'} · ${h.def.name}`;box.appendChild(face)}}
function buildWorld(){scene.clear();mixers.length=0;scene.background=new THREE.Color(0x0a1923);scene.fog=new THREE.FogExp2(0x0f232c,.011);scene.add(new THREE.HemisphereLight(0x9cc8f2,0x1c2810,1.1));let sun=new THREE.DirectionalLight(0xffdca8,2.6);sun.position.set(-25,48,18);sun.castShadow=true;sun.shadow.mapSize.set(2048,2048);sun.shadow.camera.left=-70;sun.shadow.camera.right=70;sun.shadow.camera.top=45;sun.shadow.camera.bottom=-45;scene.add(sun);
 const tex=new THREE.CanvasTexture(makeGroundTexture());tex.wrapS=tex.wrapT=THREE.RepeatWrapping;tex.repeat.set(14,7);ground=new THREE.Mesh(new THREE.PlaneGeometry(130,66),new THREE.MeshStandardMaterial({map:tex,roughness:.95,metalness:.02}));ground.rotation.x=-Math.PI/2;ground.receiveShadow=true;scene.add(ground);let laneTex=stoneTexture().clone();laneTex.needsUpdate=true;laneTex.repeat.set(20,2.6);let lane=new THREE.Mesh(new THREE.PlaneGeometry(120,16),new THREE.MeshStandardMaterial({map:laneTex,color:0x757c85,roughness:.92}));lane.rotation.x=-Math.PI/2;lane.position.y=.015;lane.receiveShadow=true;scene.add(lane);for(let x=-52;x<=52;x+=8){let slab=new THREE.Mesh(new THREE.BoxGeometry(5.6,.12,11),new THREE.MeshStandardMaterial({map:stoneTexture(),color:x%16?0x676e77:0x7a828c,roughness:.88}));slab.position.set(x,.08,0);slab.receiveShadow=true;scene.add(slab)}
 for(let i=0;i<42;i++){let side=i%2?1:-1,z=side*(11+Math.random()*18),x=-58+Math.random()*116;makeTree(x,z,rand(.7,1.45))}for(let i=0;i<24;i++)makeBush(-58+Math.random()*116,(i%2?1:-1)*rand(9,25),rand(.7,1.4));for(let i=0;i<20;i++)makeRock(-58+Math.random()*116,(i%2?1:-1)*rand(10,27),rand(.65,1.45));for(let i=0;i<18;i++)makeCrystal(-58+Math.random()*116,(i%2?1:-1)*rand(10,25),i%2?0x46cfff:0xff5577);makeRiver();}
function makeGroundTexture(){let c=document.createElement('canvas');c.width=c.height=512;let x=c.getContext('2d');let g=x.createLinearGradient(0,0,512,512);g.addColorStop(0,'#1f4a2a');g.addColorStop(.5,'#1a4123');g.addColorStop(1,'#1d4627');x.fillStyle=g;x.fillRect(0,0,512,512);for(let i=0;i<260;i++){x.fillStyle=`rgba(${10+Math.random()*25|0},${50+Math.random()*45|0},${20+Math.random()*20|0},${.08+Math.random()*.12})`;x.beginPath();x.ellipse(Math.random()*512,Math.random()*512,rand(14,60),rand(8,30),Math.random()*3.14,0,6.3);x.fill()}for(let i=0;i<9000;i++){let l=Math.random();x.fillStyle=l>.6?'#2f6a3a':l>.25?'#24502c':'#12301a';x.globalAlpha=.5;x.fillRect(Math.random()*512,Math.random()*512,1,rand(2,5));x.globalAlpha=1}for(let i=0;i<900;i++){x.fillStyle=Math.random()>.5?'#dce8b8':'#8fd08a';x.globalAlpha=.12;x.fillRect(Math.random()*512,Math.random()*512,1,2);x.globalAlpha=1}return c}
let waterTex=null,_stoneTex=null,_glowTex=null;
function stoneTexture(){if(_stoneTex)return _stoneTex;let c=document.createElement('canvas');c.width=c.height=256;let x=c.getContext('2d');x.fillStyle='#565c63';x.fillRect(0,0,256,256);for(let ty=0;ty<4;ty++)for(let tx=0;tx<5;tx++){let off=(ty%2)*32,px=tx*64-off,py=ty*64,sh=rand(-10,10);x.fillStyle=`rgb(${96+sh|0},${102+sh|0},${110+sh|0})`;x.fillRect(px+2,py+2,60,60);x.fillStyle='rgba(255,255,255,.08)';x.fillRect(px+2,py+2,60,3);x.fillStyle='rgba(0,0,0,.25)';x.fillRect(px+2,py+59,60,3)}for(let i=0;i<2600;i++){x.fillStyle=Math.random()>.5?'rgba(255,255,255,.04)':'rgba(0,0,0,.06)';x.fillRect(Math.random()*256,Math.random()*256,2,2)}_stoneTex=new THREE.CanvasTexture(c);_stoneTex.wrapS=_stoneTex.wrapT=THREE.RepeatWrapping;return _stoneTex}
function glowSprite(color,s){if(!_glowTex){let c=document.createElement('canvas');c.width=c.height=128;let x=c.getContext('2d'),g=x.createRadialGradient(64,64,4,64,64,62);g.addColorStop(0,'rgba(255,255,255,1)');g.addColorStop(.35,'rgba(255,255,255,.45)');g.addColorStop(1,'rgba(255,255,255,0)');x.fillStyle=g;x.fillRect(0,0,128,128);_glowTex=new THREE.CanvasTexture(c)}let sp=new THREE.Sprite(new THREE.SpriteMaterial({map:_glowTex,color,transparent:true,opacity:.85,blending:THREE.AdditiveBlending,depthWrite:false}));sp.scale.setScalar(s);return sp}
function makeTree(x,z,s){let g=new THREE.Group(),tr=new THREE.Mesh(new THREE.CylinderGeometry(.25,.4,2.5,7),new THREE.MeshStandardMaterial({color:0x463222})),top=new THREE.Mesh(new THREE.ConeGeometry(1.4,3.4,8),new THREE.MeshStandardMaterial({color:0x173b2a,roughness:1}));tr.position.y=1.25;top.position.y=3.4;g.add(tr,top);g.position.set(x,0,z);g.scale.setScalar(s);scene.add(g)}
function makeBush(x,z,s){let g=new THREE.Group(),mat=new THREE.MeshStandardMaterial({color:0x1e6a3d,roughness:1});for(let i=0;i<7;i++){let b=new THREE.Mesh(new THREE.ConeGeometry(.42,.95,6),mat);b.position.set(rand(-.7,.7),.45,rand(-.55,.55));b.rotation.z=rand(-.35,.35);g.add(b)}g.position.set(x,0,z);g.scale.setScalar(s);scene.add(g)}
function makeRock(x,z,s){let m=new THREE.Mesh(new THREE.DodecahedronGeometry(1,0),new THREE.MeshStandardMaterial({color:0x566267,roughness:.92}));m.position.set(x,.65*s,z);m.scale.set(s*1.25,s*.7,s);m.rotation.set(rand(-.2,.2),rand(0,6.2),rand(-.15,.15));m.castShadow=m.receiveShadow=true;scene.add(m)}
function makeCrystal(x,z,c){let m=new THREE.Mesh(new THREE.OctahedronGeometry(.45,0),new THREE.MeshStandardMaterial({color:c,emissive:c,emissiveIntensity:1.4,roughness:.25}));m.position.set(x,.55,z);scene.add(m)}
function makeRiver(){let c=document.createElement('canvas');c.width=128;c.height=512;let x=c.getContext('2d'),g=x.createLinearGradient(0,0,128,0);g.addColorStop(0,'#135266');g.addColorStop(.5,'#1d7b90');g.addColorStop(1,'#135266');x.fillStyle=g;x.fillRect(0,0,128,512);for(let i=0;i<130;i++){x.strokeStyle=`rgba(${150+Math.random()*105|0},${220+Math.random()*35|0},255,${.05+Math.random()*.12})`;x.lineWidth=rand(.6,2.2);let sx=Math.random()*128,sy=Math.random()*512;x.beginPath();x.moveTo(sx,sy);x.quadraticCurveTo(sx+rand(-14,14),sy+rand(18,50),sx+rand(-8,8),sy+rand(60,110));x.stroke()}waterTex=new THREE.CanvasTexture(c);waterTex.wrapS=waterTex.wrapT=THREE.RepeatWrapping;waterTex.repeat.set(1,3);let bank=new THREE.Mesh(new THREE.PlaneGeometry(8.8,66),new THREE.MeshStandardMaterial({color:0x122e38,roughness:1}));bank.rotation.x=-Math.PI/2;bank.position.y=.02;bank.receiveShadow=true;scene.add(bank);let r=new THREE.Mesh(new THREE.PlaneGeometry(7,66),new THREE.MeshStandardMaterial({map:waterTex,transparent:true,opacity:.82,roughness:.15,metalness:.3,emissive:0x0d3d4d,emissiveIntensity:.5}));r.rotation.x=-Math.PI/2;r.position.y=.035;scene.add(r)}

function spawnHero(id,team,pos,player=false){let root=new THREE.Group(),model=cloneSkinnedModel(templates[id]);model.scale.setScalar(3.15);model.position.y=.03;root.add(model);root.position.copy(pos);scene.add(root);tintTeam(model,team);addHeroGear(root,id,team,player);let mixer=new THREE.AnimationMixer(model),clips={};for(const a of animations[id])clips[a.name]=mixer.clipAction(a);clips.idle?.play();mixers.push(mixer);let h={kind:'hero',id,def:defs[id],team,root,model,mixer,clips,anim:'idle',pos:root.position,spawn:pos.clone(),player,hp:defs[id].hp,maxHp:defs[id].hp,mana:100,atk:defs[id].atk,range:defs[id].range,speed:defs[id].speed,dead:false,respawn:0,cd:[0,0,0,0],shield:0,buff:0,invis:0,kills:0,deaths:0,level:1,xp:0,gold:400,goldT:0,armor:0,lifesteal:0,cdr:0,items:[],lastDir:new THREE.Vector3(team? -1:1,0,0)};makeBar(h);game.heroes.push(h);if(player)game.player=h;return h}
