function fxSprite(pos,color,size,life,vel,opts={}){let sp=glowSprite(color,size);sp.position.copy(pos);scene.add(sp);game.effects.push({mesh:sp,life,maxLife:life,vel,grav:opts.grav||0,shrink:opts.shrink||0,fadeFrom:opts.fadeFrom});return sp}
function ring(pos,color,r){let mk=(rr,op,grow)=>{let m=new THREE.Mesh(new THREE.RingGeometry(rr*.86,rr,56),new THREE.MeshBasicMaterial({color,transparent:true,opacity:op,side:THREE.DoubleSide,blending:THREE.AdditiveBlending,depthWrite:false}));m.rotation.x=-Math.PI/2;m.position.copy(pos);m.position.y=.12;scene.add(m);game.effects.push({mesh:m,life:.5,grow})};mk(r,1,2.2);mk(r*.6,.5,3.4);fxSprite(pos.clone().add(new THREE.Vector3(0,.5,0)),color,r*1.5,.26,null,{shrink:-1.6})}
